import React, { createContext, useState, useContext, useEffect, useCallback, useOptimistic } from 'react';
import axios from 'axios';
import API from './API';

axios.defaults.baseURL = API;

const AuthContext = createContext();

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [token, setToken] = useState(localStorage.getItem('token'));
  const [loading, setLoading] = useState(true);
  const [users, setUsers] = useState([]);
  
  // Use useOptimistic for optimistic updates
  const [optimisticUsers, addOptimisticUser] = useOptimistic(
    users,
    (state, newUser) => [...state, newUser]
  );

  // Set axios default header
  useEffect(() => {
    if (token) {
      axios.defaults.headers.common['Authorization'] = `Bearer ${token}`;
    } else {
      delete axios.defaults.headers.common['Authorization'];
    }
  }, [token]);

  // Fetch current user
  useEffect(() => {
    const fetchUser = async () => {
      if (!token) {
        setLoading(false);
        return;
      }
      
      try {
        const res = await axios.get('/api/auth/me');
        setUser(res.data.user);
        await fetchActiveUsers();
      } catch (error) {
        console.error('Auth error:', error);
        localStorage.removeItem('token');
        setToken(null);
        setUser(null);
      } finally {
        setLoading(false);
      }
    };

    fetchUser();
  }, [token]);

  const fetchActiveUsers = useCallback(async () => {
    try {
      const res = await axios.get('/api/users/active');
      setUsers(res.data);
    } catch (error) {
      console.error('Error fetching active users:', error);
    }
  }, []);

  const login = useCallback(async (username, password) => {
    try {
      const res = await axios.post('/api/auth/login', { username, password });
      const { token: newToken, user: userData } = res.data;
      
      localStorage.setItem('token', newToken);
      setToken(newToken);
      setUser(userData);
      await fetchActiveUsers();
      
      return { success: true };
    } catch (error) {
      return { 
        success: false, 
        error: error.response?.data?.error || 'Login failed' 
      };
    }
  }, [fetchActiveUsers]);

  const logout = useCallback(async () => {
    try {
      if (token) {
        await axios.post('/api/auth/logout');
      }
    } catch (error) {
      console.error('Logout error:', error);
    }
    
    localStorage.removeItem('token');
    setToken(null);
    setUser(null);
    setUsers([]);
  }, [token]);

  const value = {
    user,
    token,
    loading,
    users: optimisticUsers,
    login,
    logout,
    fetchActiveUsers,
    addOptimisticUser
  };

  return (
    <AuthContext.Provider value={value}>
      {children}
    </AuthContext.Provider>
  );
};